import { NgClass } from '@angular/common';
import { Component, Input } from '@angular/core';
import { RouterLink } from '@angular/router';

export interface HeroAction {
  label: string;
  url: string;
  external?: boolean;
}

@Component({
  selector: 'app-hero',
  standalone: true,
  imports: [NgClass, RouterLink],
  templateUrl: './hero.component.html',
  styleUrl: './hero.component.sass'
})
export class HeroComponent {
  @Input() image = '';
  @Input({ required: true }) title = '';
  @Input() subtitle = '';
  @Input() eyebrow = '';
  @Input() ctaPrimary: HeroAction | null = null;
  @Input() ctaSecondary: HeroAction | null = null;
  @Input() height: 'fullscreen' | 'large' | 'compact' = 'large';
  @Input() alignment: 'start' | 'center' = 'start';

  protected get backgroundStyle(): string {
    return `linear-gradient(180deg, rgba(20, 18, 16, 0.25), rgba(20, 18, 16, 0.72)), url('${this.image}')`;
  }
}
